    msg = recv_bcm_message(can_bus)
    assert get_bdy_parking_lamp(msg.data) == 0

def test_tc_pl_002_on(can_bus):
    msg = recv_bcm_message(can_bus)
    assert get_bdy_parking_lamp(msg.data) == 1

def test_tc_pl_003_transition_on(can_bus):
    msg = recv_bcm_message(can_bus)
    assert get_bdy_parking_lamp(msg.data) == 1
